const item = $input.first().json;

let errorMessage = '';
let failedNode = '';
let executionId = '';
let executionUrl = '';
let mode = '';
let workflowName = item.workflow?.name || 'Unknown';
let workflowId = item.workflow?.id || 'Unknown';

if (item.execution) {
  // Schema 1: error in a regular (non-trigger) node
  errorMessage = item.execution.error?.message || 'Unknown';
  failedNode = item.execution.lastNodeExecuted || 'Unknown';
  executionId = item.execution.id || 'N/A';
  executionUrl = item.execution.url || 'N/A';
  mode = item.execution.mode || 'Unknown';
} else if (item.trigger) {
  // Schema 2: error in the trigger node itself
  errorMessage = item.trigger.error?.message || 'Unknown';
  failedNode = 'Trigger Node (workflow did not execute)';
  executionId = 'N/A (trigger-level failure)';
  executionUrl = 'N/A (trigger-level failure)';
  mode = item.trigger.mode || 'trigger';
}

// Classify priority: LOW = transient API errors, HIGH = logic/config failures
const lowPriorityPatterns = [
  /\b503\b/, /\b500\b/, /\b429\b/,
  /rate.?limit/i, /service.?unavailable/i, /too.?many.?requests/i,
  /timeout/i, /temporarily unavailable/i, /ECONNRESET/i, /ETIMEDOUT/i,
  /bad gateway/i, /gateway timeout/i
];
const isLowPriority = lowPriorityPatterns.some(p => p.test(errorMessage));
const priority = isLowPriority ? 'LOW' : 'HIGH';

const priorityLabel = priority === 'LOW'
  ? 'LOW — Temporary API outage (503/500/429). Usually self-resolves within minutes.'
  : 'HIGH — Logic or configuration failure. Requires investigation.';

const recommendedAction = priority === 'LOW'
  ? 'No action needed — temporary API issue, usually self-resolves within minutes.'
  : 'Action required — please investigate. Technical details below.';

return [{
  json: {
    workflowName,
    workflowId,
    errorMessage,
    failedNode,
    executionId,
    executionUrl,
    mode,
    priority,
    priorityLabel,
    recommendedAction
  }
}];
